import os
import subprocess
import sys

def validate_path(path):
    if os.path.isdir(path):
        return os.path.abspath(path)
    else:
        raise ValueError("Invalid directory path.")

def create_backup(directory, format):
    validated_path = validate_path(directory)
    base_name = os.path.basename(validated_path)
    
    if format == 'tar.gz':
        subprocess.run(['tar', '-czf', f'{base_name}.tar.gz', validated_path])
    elif format == 'tar.bz2':
        subprocess.run(['tar', '-cjf', f'{base_name}.tar.bz2', validated_path])
    elif format == 'zip':
        subprocess.run(['zip', '-r', f'{base_name}.zip', validated_path])
    elif format == '7z':
        subprocess.run(['7z', 'a', f'{base_name}.7z', validated_path])
    else:
        raise ValueError("Unsupported format.")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup.py <directory_path> <format>")
